import random

class DSU:
    def __init__(self, n):
        self.parent = list(range(n))
        self.num_sets = n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)
        if root_i != root_j:
            self.parent[root_i] = root_j
            self.num_sets -= 1
            return True
        return False

def kargers_min_cut(vertices, edges, iterations=None):
    n = len(vertices)
    if n < 2:
        return 0
    if n == 2:
        return len(edges)

    min_cut_size = float('inf')

    if iterations is None:
        iterations = n * n * 5

    for _ in range(iterations):
        dsu = DSU(n)

        while dsu.num_sets > 2:
            if not edges:
                break

            edge_index = random.randrange(len(edges))
            u, v = edges[edge_index]

            dsu.union(u, v)

        if dsu.num_sets == 2:
            cut_size = 0

            root1 = -1
            for i in range(n):
                root_i = dsu.find(i)
                if root1 == -1:
                    root1 = root_i
                elif root_i != root1:
                    root2 = root_i
                    break

            for u, v in edges:
                if (dsu.find(u) == root1 and dsu.find(v) == root2) or \
                   (dsu.find(u) == root2 and dsu.find(v) == root1):
                    cut_size += 1

            min_cut_size = min(min_cut_size, cut_size)

    if min_cut_size == float('inf'):
        return 0

    return min_cut_size
